#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_N 50
#define MAX_M 200

int N, M, W;
int graph[MAX_N][MAX_N];
int colors[MAX_N];

void bfs(int start) {
    int queue[MAX_N];
    int front = 0, rear = 0;
    queue[rear++] = start;
    colors[start] = 1;
    while (front < rear) {
        int u = queue[front++];
        for (int v = 0; v < N; v++) {
            if (graph[u][v] && colors[v] == 0) {
                queue[rear++] = v;
                colors[v] = 3 - colors[u];
            }
        }
    }
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &M);
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                graph[i][j] = 0;
            }
        }
        for (int i = 0; i < M; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            u--; v--;
            graph[u][v] = graph[v][u] = 1;
        }
        scanf("%d", &W);
        int warped[M];
        for (int i = 0; i < W; i++) {
            scanf("%d", &warped[i]);
        }
        for (int i = 0; i < N; i++) {
            colors[i] = 0;
        }
        for (int i = 0; i < N; i++) {
            if (colors[i] == 0) {
                bfs(i);
            }
        }
        int possible = 1;
        for (int i = 0; i < M; i++) {
            int u, v;
            for (u = 0; u < N; u++) {
                for (v = 0; v < N; v++) {
                    if (graph[u][v] && colors[u] == colors[v]) {
                        possible = 0;
                        break;
                    }
                }
                if (!possible) break;
            }
        }
        if (possible) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

