    static final int MAX_N = 50;
    static final int MAX_M = 200;
    static int N, M, W;
    static int[][] graph;
    static int[] colors;

    public static void bfs(int start) {
        Queue<Integer> q = new LinkedList<>();
        q.add(start);
        colors[start] = 1;
        while (!q.isEmpty()) {
            int u = q.poll();
            for (int v = 0; v < N; v++) {
                if (graph[u][v] == 1 && colors[v] == 0) {
                    q.add(v);
                    colors[v] = 3 - colors[u];
                }
            }
        }
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            N = sc.nextInt();
            M = sc.nextInt();
            graph = new int[N][N];
            colors = new int[N];
            for (int i = 0; i < M; i++) {
                int u = sc.nextInt() - 1;
                int v = sc.nextInt() - 1;
                graph[u][v] = graph[v][u] = 1;
            }
            W = sc.nextInt();
            int[] warped = new int[W];
            for (int i = 0; i < W; i++) {
                warped[i] = sc.nextInt();
            }
            for (int i = 0; i < N; i++) {
                if (colors[i] == 0) {
                    bfs(i);
                }
            }
            boolean possible = true;
            for (int i = 0; i < M; i++) {
                for (int u = 0; u < N; u++) {
                    for (int v = 0; v < N; v++) {
                        if (graph[u][v] == 1 && colors[u] == colors[v]) {
                            possible = false;
                            break;
                        }
                    }
                    if (!possible) break;
                }
            }
            if (possible) {
                System.out.println("YES");
            } else {
                System.out.println("NO");
            }
        }
    }
}

